'use client'

import { useState, useEffect } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'

const API_BASE = 'http://localhost:3002'

const labels = {
  classification: { SELF: '자가', OTHER: '타기관', HEARDOTCOM: '히어닷컴' },
  governmentSupport: { 
    DISABILITY_GRADE_HOLDER: '장애등급', 
    POTENTIAL_DISABILITY: '장애가망', 
    INDUSTRIAL_ACCIDENT: '산업재해', 
    GENERAL: '일반' 
  },
  recipient: { RECIPIENT: '수급자', NEAR_POVERTY: '차상위', GENERAL: '일반' },
  lossType: { CONDUCTIVE: '전음성', SENSORINEURAL: '감각신경성', SUDDEN: '돌발성', NOISE_INDUCED: '소음성' }
}

interface Customer {
  id: string
  name: string
  contactNumber: string
  classification: string
  governmentSupportType?: string
  recipientType?: string
  lossType?: string
  birthDate: string | null
  gender: string | null
  createdAt: string
}

export default function CustomersPage() {
  const router = useRouter()
  const [customers, setCustomers] = useState<Customer[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [showModal, setShowModal] = useState(false)
  const [form, setForm] = useState({
    name: '', contactNumber: '', classification: 'SELF',
    birthDate: '', gender: '', email: '', memo: '',
    governmentSupportType: '', recipientType: '', processType: '',
    lossType: '', referralSource: '', hospitalName: ''
  })
  const [submitting, setSubmitting] = useState(false)

  const fetchCustomers = () => {
    fetch(`${API_BASE}/api/customers`)
      .then(r => r.json())
      .then(data => {
        setCustomers(data.items ?? data)
        setLoading(false)
      })
      .catch(() => setLoading(false))
  }

  useEffect(() => { fetchCustomers() }, [])

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!form.name || !form.contactNumber) return
    setSubmitting(true)
    try {
      const res = await fetch(`${API_BASE}/api/customers`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          centerId: localStorage.getItem('centerId') || 'default-center-id',
          name: form.name,
          contactNumber: form.contactNumber,
          classification: form.classification || undefined,
          birthDate: form.birthDate || undefined,
          gender: form.gender || undefined,
          email: form.email || undefined,
          memo: form.memo || undefined,
          governmentSupportType: form.governmentSupportType || undefined,
          recipientType: form.recipientType || undefined,
          processType: form.processType || undefined,
          lossType: form.lossType || undefined,
          referralSource: form.referralSource || undefined,
          hospitalName: form.hospitalName || undefined,
        }),
      })
      if (!res.ok) throw new Error()
      const created = await res.json()
      setShowModal(false)
      setForm({ name: '', contactNumber: '', classification: 'SELF', birthDate: '', gender: '', email: '', memo: '', governmentSupportType: '', recipientType: '', processType: '', lossType: '', referralSource: '', hospitalName: '' })
      fetchCustomers()
      router.push(`/customers/${created.id}`)
    } catch {
      alert('고객 등록에 실패했습니다')
    } finally {
      setSubmitting(false)
    }
  }

  const filtered = customers.filter(c =>
    c.name.includes(search) || c.contactNumber.includes(search)
  )

  const classificationColors: Record<string, string> = {
    SELF: 'bg-blue-100 text-blue-700',
    OTHER: 'bg-green-100 text-green-700',
    HEARDOTCOM: 'bg-purple-100 text-purple-700'
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">고객 관리</h1>
          <p className="text-sm text-slate-500 mt-1">총 {filtered.length}명</p>
        </div>
        <button
          onClick={() => setShowModal(true)}
          className="btn btn-primary shadow-lg shadow-blue-500/30"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" />
          </svg>
          새 고객 등록
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm p-4">
        <input
          type="text"
          placeholder="이름 또는 전화번호 검색..."
          value={search}
          onChange={e => setSearch(e.target.value)}
          className="w-full max-w-sm px-4 py-2 rounded-xl border border-slate-200 bg-white shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
      </div>

      {loading ? (
        <div className="text-slate-400 py-20 text-center">불러오는 중...</div>
      ) : filtered.length === 0 ? (
        <div className="text-slate-400 py-20 text-center bg-white rounded-xl shadow-sm">고객이 없습니다.</div>
      ) : (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200">
                <th className="text-left px-6 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wider">이름</th>
                <th className="text-left px-6 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wider">연락처</th>
                <th className="text-left px-6 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wider">분류</th>
                <th className="text-left px-6 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wider">정부지원</th>
                <th className="text-left px-6 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wider">수급구분</th>
                <th className="text-left px-6 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wider">등록일</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filtered.map(c => (
                <tr key={c.id} className="hover:bg-blue-50/40 transition-colors cursor-pointer" onClick={() => router.push(`/customers/${c.id}`)}>
                  <td className="px-6 py-4">
                    <span className="font-semibold text-slate-900">{c.name}</span>
                  </td>
                  <td className="px-6 py-4 text-slate-600">{c.contactNumber}</td>
                  <td className="px-6 py-4">
                    <span className={`px-2.5 py-1 rounded-full text-xs font-medium ${classificationColors[c.classification as keyof typeof classificationColors] || 'bg-slate-100 text-slate-600'}`}>
                      {labels.classification[c.classification as keyof typeof labels.classification] || c.classification}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-500">
                    {c.governmentSupportType ? labels.governmentSupport[c.governmentSupportType as keyof typeof labels.governmentSupport] || c.governmentSupportType : '-'}
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-500">
                    {c.recipientType ? labels.recipient[c.recipientType as keyof typeof labels.recipient] || c.recipientType : '-'}
                  </td>
                  <td className="px-6 py-4 text-slate-400 text-sm">
                    {new Date(c.createdAt).toLocaleDateString('ko-KR')}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4" onClick={() => setShowModal(false)}>
          <div className="bg-white rounded-xl w-full max-w-2xl max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
            <div className="p-6 border-b border-slate-200 flex items-center justify-between sticky top-0 bg-white">
              <h2 className="text-xl font-bold text-slate-900">새 고객 등록</h2>
              <button onClick={() => setShowModal(false)} className="w-8 h-8 rounded-lg bg-slate-100 hover:bg-slate-200 flex items-center justify-center">
                <svg className="w-5 h-5 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">이름 <span className="text-red-500">*</span></label>
                  <input type="text" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} className="input" placeholder="홍길동" required />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">연락처 <span className="text-red-500">*</span></label>
                  <input type="text" value={form.contactNumber} onChange={e => setForm({ ...form, contactNumber: e.target.value })} className="input" placeholder="010-0000-0000" required />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">분류</label>
                  <select value={form.classification} onChange={e => setForm({ ...form, classification: e.target.value })} className="input">
                    <option value="SELF">자가</option>
                    <option value="OTHER">타기관</option>
                    <option value="HEARDOTCOM">히어닷컴</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">성별</label>
                  <select value={form.gender} onChange={e => setForm({ ...form, gender: e.target.value })} className="input">
                    <option value="">선택</option>
                    <option value="MALE">남성</option>
                    <option value="FEMALE">여성</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">생년월일</label>
                  <input type="date" value={form.birthDate} onChange={e => setForm({ ...form, birthDate: e.target.value })} className="input" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">이메일</label>
                  <input type="email" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} className="input" placeholder="example@email.com" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">정부지원유형</label>
                  <select value={form.governmentSupportType} onChange={e => setForm({ ...form, governmentSupportType: e.target.value })} className="input">
                    <option value="">선택</option>
                    <option value="DISABILITY_GRADE_HOLDER">장애등급소지자</option>
                    <option value="POTENTIAL_DISABILITY">장애가망</option>
                    <option value="INDUSTRIAL_ACCIDENT">산업재해</option>
                    <option value="GENERAL">일반</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">수급구분</label>
                  <select value={form.recipientType} onChange={e => setForm({ ...form, recipientType: e.target.value })} className="input">
                    <option value="">선택</option>
                    <option value="RECIPIENT">수급자 (지자체 100%)</option>
                    <option value="NEAR_POVERTY">차상위 (공단 100%)</option>
                    <option value="GENERAL">일반 (공단 90%)</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">인증유형</label>
                  <select value={form.processType} onChange={e => setForm({ ...form, processType: e.target.value })} className="input">
                    <option value="">선택</option>
                    <option value="PRE_CERTIFICATION">사전인증</option>
                    <option value="POST_CERTIFICATION">사후인증</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">청력장애유형</label>
                  <select value={form.lossType} onChange={e => setForm({ ...form, lossType: e.target.value })} className="input">
                    <option value="">선택</option>
                    <option value="CONDUCTIVE">전음성</option>
                    <option value="SENSORINEURAL">감각신경성</option>
                    <option value="SUDDEN">돌발성</option>
                    <option value="NOISE_INDUCED">소음성</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">유입경로</label>
                  <input type="text" value={form.referralSource} onChange={e => setForm({ ...form, referralSource: e.target.value })} className="input" placeholder="지인추천, 병원등" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">병원</label>
                  <input type="text" value={form.hospitalName} onChange={e => setForm({ ...form, hospitalName: e.target.value })} className="input" placeholder="비뢰 ENT 등" />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">메모</label>
                <textarea value={form.memo} onChange={e => setForm({ ...form, memo: e.target.value })} className="input resize-none" rows={3} placeholder="특이사항..." />
              </div>
              <div className="flex justify-end gap-3 pt-4 border-t">
                <button type="button" onClick={() => setShowModal(false)} className="btn btn-secondary">취소</button>
                <button type="submit" disabled={submitting} className="btn btn-primary">
                  {submitting ? '등록 중...' : '✓ 고객 등록'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}